177â†’/// Compute a hash representing the "path signature" of an execution.
178â†’///
179â†’/// When `scope_events` is non-empty, uses scope-aware collapsing: repeated
180â†’/// invocations of the same loop or call scope are collapsed to the sorted set
181â†’/// of unique `(branch_id, taken)` pairs. The `buckets` parameter controls
182â†’/// whether iteration counts also contribute to the hash â€” when enabled,
183â†’/// different iteration count buckets produce different hashes even if the
184â†’/// branch profile is identical.
185â†’///
186â†’/// Falls back to legacy sequential hashing when `scope_events` is empty.
187â†’pub(crate) fn path_hash(result: &crate::protocol::ExecuteResult, buckets: &LoopBuckets) -> u64 {
188â†’    if !result.scope_events.is_empty() {
189â†’        return scope_aware_hash(&result.scope_events, buckets);
190â†’    }
191â†’    legacy_path_hash(result)
192â†’}
193â†’
194â†’/// Legacy path hash: hashes branch decisions sequentially, falling back to
195â†’/// lines_executed, error info, or return value.
196â†’fn legacy_path_hash(result: &crate::protocol::ExecuteResult) -> u64 {
197â†’    let mut hasher = DefaultHasher::new();
198â†’    if !result.branch_path.is_empty() {
199â†’        for decision in &result.branch_path {
200â†’            decision.branch_id.hash(&mut hasher);
201â†’            decision.taken.hash(&mut hasher);
202â†’        }
203â†’    } else if !result.lines_executed.is_empty() {
204â†’        result.lines_executed.hash(&mut hasher);
205â†’    } else if let Some(ref err) = result.thrown_error {
206â†’        "error".hash(&mut hasher);
207â†’        err.error_type.hash(&mut hasher);
208â†’        err.message.hash(&mut hasher);
209â†’    } else {
210â†’        "ok".hash(&mut hasher);
211â†’        let ret_str = serde_json::to_string(&result.return_value).unwrap_or_default();
212â†’        ret_str.hash(&mut hasher);
213â†’    }
214â†’    hasher.finish()
215â†’}
216â†’
217â†’/// Scope-aware path hash that collapses repeated loop/call scopes.
218â†’///
219â†’/// Parses the flat trace into a tree of nested scopes, then for each scope_id
220â†’/// that appears multiple times at the same nesting level, collapses all
221â†’/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
222â†’/// When `buckets` is non-empty, each distinct profile is also paired with
223â†’/// its iteration-count bucket so that different iteration counts produce
224â†’/// different hashes.
225â†’fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
226â†’    use crate::execution_record::{ScopeEvent, TraceEvent};
227â†’    use std::collections::BTreeSet;
228â†’
229â†’    /// Discriminant tag for scope enter/exit matching.
230â†’    #[derive(Clone, Copy, PartialEq)]
231â†’    enum ScopeKind {
232â†’        Loop(u32),
233â†’        Call(u32),
234â†’    }
235â†’
236â†’    /// A sorted branch profile from one loop/call iteration.
237â†’    type BranchProfile = Vec<(u32, bool)>;
238â†’
239â†’    /// A profile paired with its optional iteration-count bucket.
240â†’    type ProfileWithBucket = (BranchProfile, Option<u32>);
241â†’
242â†’    /// Collapsed representation of a scope's content for hashing.
243â†’    #[derive(Hash)]
244â†’    enum CollapsedItem {
245â†’        /// A branch decision outside any scope at this level.
246â†’        Branch { branch_id: u32, taken: bool },
247â†’        /// A collapsed scope: set of distinct per-iteration branch profiles,
248â†’        /// each paired with its iteration-count bucket (or `None` when
249â†’        /// bucketing is disabled, preserving backward-compat hashing).
250â†’        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
251â†’    }
252â†’
253â†’    fn is_matching_exit(event: &TraceEvent, kind: ScopeKind) -> bool {
254â†’        match (kind, event) {
255â†’            (ScopeKind::Loop(id), TraceEvent::Scope { event: ScopeEvent::LoopExit { loop_id } }) => *loop_id == id,
256â†’            (ScopeKind::Call(id), TraceEvent::Scope { event: ScopeEvent::CallExit { call_site_id } }) => *call_site_id == id,
257â†’            _ => false,
258â†’        }
259â†’    }
260â†’
261â†’    /// Convert accumulated per-scope profile maps into `CollapsedItem::Scope`
262â†’    /// entries appended to `items`. Called at both the normal end of `collapse()`
263â†’    /// and the early return on parent-scope exit â€” without this, nested scopes
264â†’    /// would be invisible to their parent's branch profile.
265â†’    fn emit_scope_items(
266â†’        items: &mut Vec<CollapsedItem>,
267â†’        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
268â†’        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
269â†’        buckets: &LoopBuckets,
270â†’    ) {
271â†’        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
272â†’        for (id, profiles) in loop_profiles {
273â†’            let tag = (*id as u64) | (1u64 << 32);
274â†’            let mut sorted: Vec<ProfileWithBucket> = profiles
275â†’                .iter()
276â†’                .map(|(profile, &count)| {
277â†’                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
278â†’                    (profile.clone(), bucket)
279â†’                })
280â†’                .collect();
281â†’            sorted.sort();
282â†’            scope_ids.push((tag, sorted));
283â†’        }
284â†’        for (id, profiles) in call_profiles {
285â†’            let tag = (*id as u64) | (2u64 << 32);
286â†’            let mut sorted: Vec<ProfileWithBucket> = profiles
287â†’                .iter()
288â†’                .map(|(profile, &count)| {
289â†’                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
290â†’                    (profile.clone(), bucket)
291â†’                })
292â†’                .collect();
293â†’            sorted.sort();
294â†’            scope_ids.push((tag, sorted));
295â†’        }
296â†’        scope_ids.sort_by_key(|(tag, _)| *tag);
297â†’        for (scope_tag, profile_buckets) in scope_ids {
298â†’            items.push(CollapsedItem::Scope { scope_tag, profile_buckets });
299â†’        }
300â†’    }
301â†’
302â†’    fn collapse(events: &[TraceEvent], buckets: &LoopBuckets) -> (Vec<CollapsedItem>, usize) {
303â†’        let mut items: Vec<CollapsedItem> = Vec::new();
304â†’        let mut loop_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
305â†’        let mut call_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
306â†’
307â†’        let mut i = 0;
308â†’        while i < events.len() {
309â†’            match &events[i] {
310â†’                TraceEvent::Branch { decision } => {
311â†’                    items.push(CollapsedItem::Branch {
312â†’                        branch_id: decision.branch_id,
313â†’                        taken: decision.taken,
314â†’                    });
315â†’                    i += 1;
316â†’                }
317â†’                TraceEvent::Scope { event } => {
318â†’                    let (kind, is_enter) = match event {
319â†’                        ScopeEvent::LoopEnter { loop_id } => (ScopeKind::Loop(*loop_id), true),
320â†’                        ScopeEvent::LoopExit { loop_id } => (ScopeKind::Loop(*loop_id), false),
321â†’                        ScopeEvent::CallEnter { call_site_id } => (ScopeKind::Call(*call_site_id), true),
322â†’                        ScopeEvent::CallExit { call_site_id } => (ScopeKind::Call(*call_site_id), false),
323â†’                    };
324â†’
325â†’                    if !is_enter {
326â†’                        // Exit without matching enter â€” we've hit the boundary
327â†’                        // of our parent scope. Emit accumulated scope items
328â†’                        // before returning so nested scopes are visible to
329â†’                        // the parent's branch profile.
330â†’                        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
331â†’                        return (items, i);
332â†’                    }
333â†’
334â†’                    // Recursively collapse the scope body
335â†’                    let body_start = i + 1;
336â†’                    let (child_items, consumed) = collapse(&events[body_start..], buckets);
337â†’                    let body_end = body_start + consumed;
338â†’
339â†’                    // Build this iteration's branch profile (sorted for determinism)
340â†’                    let mut profile = BTreeSet::new();
341â†’                    for item in &child_items {
342â†’                        match item {
343â†’                            CollapsedItem::Branch { branch_id, taken } => {
344â†’                                profile.insert((*branch_id, *taken));
345â†’                            }
346â†’                            CollapsedItem::Scope { scope_tag, profile_buckets } => {
347â†’                                let mut h = DefaultHasher::new();
348â†’                                scope_tag.hash(&mut h);
349â†’                                profile_buckets.hash(&mut h);
350â†’                                let synthetic_id = (h.finish() & 0x7FFF_FFFF) as u32 | 0x8000_0000;
351â†’                                profile.insert((synthetic_id, true));
352â†’                            }
353â†’                        }
354â†’                    }
355â†’                    let profile_vec: Vec<(u32, bool)> = profile.into_iter().collect();
356â†’
357â†’                    // Increment iteration count for this (scope_id, profile) pair
358â†’                    match kind {
359â†’                        ScopeKind::Loop(id) => {
360â†’                            *loop_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
361â†’                        }
362â†’                        ScopeKind::Call(id) => {
363â†’                            *call_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
364â†’                        }
365â†’                    }
366â†’
367â†’                    // Skip past the exit event if present
368â†’                    i = body_end;
369â†’                    if i < events.len() && is_matching_exit(&events[i], kind) {
370â†’                        i += 1;
371â†’                    }
372â†’                }
373â†’            }
374â†’        }
375â†’
376â†’        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
377â†’        (items, events.len())
378â†’    }
379â†’
380â†’    let (items, _) = collapse(events, buckets);
381â†’    let mut hasher = DefaultHasher::new();
382â†’    for item in &items {
383â†’        item.hash(&mut hasher);
384â†’    }
385â†’    hasher.finish()
386â†’}
