260â†’/// Convert Z3 `ConcreteValue`s back into JSON values suitable for the Execute protocol.
261â†’///
262â†’/// For `Complex` values, produces a `__complex_type` tagged JSON object.
263â†’/// The solver unwraps complex types to their repr for solving, but when
264â†’/// converting back to JSON we need to re-wrap with the type tag so the
265â†’/// frontend can reconstruct the native value.
266â†’pub(crate) fn concrete_to_json(value: &ConcreteValue) -> serde_json::Value {
267â†’    match value {
268â†’        ConcreteValue::Int(i) => serde_json::json!(*i),
269â†’        ConcreteValue::Float(f) => serde_json::json!(*f),
270â†’        ConcreteValue::Str(s) => serde_json::json!(s),
271â†’        ConcreteValue::Bool(b) => serde_json::json!(*b),
272â†’        ConcreteValue::Complex { kind, repr } => {
273â†’            // Serialize the kind to its snake_case name for the wire format
274â†’            let kind_str = serde_json::to_value(kind)
275â†’                .ok()
276â†’                .and_then(|v| v.as_str().map(|s| s.to_string()))
277â†’                .unwrap_or_else(|| format!("{kind:?}").to_lowercase());
278â†’            let repr_json = concrete_to_json(repr);
279â†’            // Build tagged wire format: {"__complex_type": "<kind>", "value": <repr>}
280â†’            serde_json::json!({
281â†’                "__complex_type": kind_str,
282â†’                "value": repr_json,
283â†’            })
284â†’        }
285â†’    }
286â†’}
