288â†’/// Build a new input vector by overlaying Z3-solved values onto existing inputs.
289â†’///
290â†’/// The solver returns variable names like "x", "config.timeout" etc. We match
291â†’/// these against parameter names in `base_inputs` (positionally). For now we
292â†’/// support simple flat parameters â€” if the variable name matches the parameter
293â†’/// index convention (param_0, param_1, â€¦) or the base is a single param, we
294â†’/// update it directly.
295â†’#[requires(base_inputs.len() == param_names.len(), "base_inputs and param_names must be positionally aligned")]
296â†’#[contracts::ensures(ret.len() == base_inputs.len(), "overlay must preserve input vector length")]
297â†’pub(crate) fn overlay_solved_values(
298â†’    base_inputs: &[serde_json::Value],
299â†’    solved: &std::collections::HashMap<String, ConcreteValue>,
300â†’    param_names: &[String],
301â†’) -> Vec<serde_json::Value> {
302â†’    let mut result = base_inputs.to_vec();
303â†’
304â†’    for (var_name, value) in solved {
305â†’        // Try to match variable name to a parameter by name.
306â†’        if let Some(idx) = param_names.iter().position(|n| n == var_name) {
307â†’            if idx < result.len() {
308â†’                result[idx] = concrete_to_json(value);
309â†’            }
310â†’        } else if param_names.len() == 1 && base_inputs.len() == 1 && !var_name.contains('.') {
311â†’            // Single-param function with a simple (non-derived) variable name:
312â†’            // the solver variable likely refers to the param. Skip derived names
313â†’            // like "email.length" which are internal Z3 variables, not params.
314â†’            result[0] = concrete_to_json(value);
315â†’        }
316â†’    }
317â†’
318â†’    result
319â†’}
