324â†’/// `seed_inputs` provides initial input sets to begin exploration.
325â†’/// `user_inputs` provides user-provided candidate inputs (highest priority).
326â†’/// `param_infos` provides parameter metadata including names and types. Names are
327â†’/// used to map Z3 variables back to parameter positions; types are used to declare
328â†’/// correct Z3 sorts (preventing string params from being declared as Int).
329â†’pub async fn explore(
330â†’    frontend: &mut Frontend,
331â†’    function_name: &str,
332â†’    seed_inputs: Vec<Vec<serde_json::Value>>,
333â†’    user_inputs: Vec<Vec<serde_json::Value>>,
334â†’    param_infos: &[ParamInfo],
335â†’    config: &ExploreConfig,
336â†’) -> Result<ExploreResult, ExploreError> {
337â†’    let param_names: Vec<String> = param_infos.iter().map(|p| p.name.clone()).collect();
338â†’    let mut worklist = BinaryHeap::new();
339â†’    let mut covered_paths: HashSet<u64> = HashSet::new();
340â†’    let mut executions = Vec::new();
341â†’    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
342â†’    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
343â†’    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
344â†’    let mut total_executions: usize = 0;
345â†’    let mut z3_generated: usize = 0;
346â†’    let mut fuzz_generated: usize = 0;
347â†’    let mut drill_generated: usize = 0;
348â†’    let mut plateau_counter: usize = 0;
349â†’    let mut termination_reason = TerminationReason::WorklistExhausted;
350â†’    let mut seen_branch_sides: HashSet<(u32, bool)> = HashSet::new();
351â†’    let mut frontier_set = FrontierSet::new();
352â†’    let mut rng = StdRng::from_os_rng();
353â†’    let mut triage_state = TriageState::new(param_names.clone());
354â†’    let mut triage_skipped: usize = 0;
355â†’    let mut triage_mispredictions: usize = 0;
356â†’
357â†’    // Add user-provided candidates with highest priority.
358â†’    for inputs in user_inputs {
359â†’        worklist.push(WorklistEntry {
360â†’            inputs,
361â†’            source: InputSource::UserProvided,
362â†’        });
363â†’    }
364â†’
365â†’    // Seed the worklist.
366â†’    for inputs in seed_inputs {
367â†’        worklist.push(WorklistEntry {
368â†’            inputs,
369â†’            source: InputSource::Seed,
370â†’        });
371â†’    }
372â†’
373â†’    // --- Float probe phase ---
374â†’    let float_indices = crate::float_probe::float_param_indices(param_infos);
375â†’    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
376â†’    if !float_indices.is_empty() {
377â†’        for &idx in &float_indices {
378â†’            let pairs = crate::float_probe::generate_probe_pairs(
379â†’                param_infos,
380â†’                idx,
381â†’                crate::float_probe::PROBE_COUNT,
382â†’                &mut rng,
383â†’            );
384â†’            let mut agreements = 0usize;
385â†’            let mut total_probes = 0usize;
386â†’            let mut divergent_values = Vec::new();
387â†’
388â†’            for (float_inputs, floor_inputs) in pairs {
389â†’                // Execute with float value.
390â†’                let float_resp = frontend
391â†’                    .send(Command::Execute {
392â†’                        function: function_name.to_string(),
393â†’                        inputs: float_inputs.clone(),
394â†’                        mocks: config.mocks.clone(),
395â†’                        setup_context: None,
396â†’                    })
397â†’                    .await?;
398â†’
399â†’                // Execute with floor value.
400â†’                let floor_resp = frontend
401â†’                    .send(Command::Execute {
402â†’                        function: function_name.to_string(),
403â†’                        inputs: floor_inputs,
404â†’                        mocks: config.mocks.clone(),
405â†’                        setup_context: None,
406â†’                    })
407â†’                    .await?;
408â†’
409â†’                if let (
410â†’                    ResponseResult::Execute(float_result),
411â†’                    ResponseResult::Execute(floor_result),
412â†’                ) = (&float_resp.result, &floor_resp.result) {
413â†’                    total_probes += 1;
414â†’
415â†’                    if crate::float_probe::executions_agree(float_result, floor_result) {
416â†’                        agreements += 1;
417â†’                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
418â†’                        divergent_values.push(v);
419â†’                    }
420â†’                }
421â†’            }
422â†’
423â†’            let classification = crate::float_probe::classify(
424â†’                agreements,
425â†’                total_probes,
426â†’                crate::float_probe::AGREEMENT_THRESHOLD,
427â†’            );
428â†’            float_probe_results.push(crate::float_probe::FloatProbeResult {
429â†’                param_index: idx,
430â†’                param_name: param_infos[idx].name.clone(),
431â†’                classification,
432â†’                agreements,
433â†’                total_probes,
434â†’                divergent_values,
435â†’            });
436â†’        }
437â†’    }
438â†’
439â†’    let explore_start = Instant::now();
440â†’
441â†’    while let Some(entry) = worklist.pop() {
442â†’        if executions.len() >= config.max_iterations {
443â†’            termination_reason = TerminationReason::MaxIterations;
444â†’            break;
445â†’        }
446â†’        if total_executions >= config.max_executions {
447â†’            termination_reason = TerminationReason::MaxExecutions;
448â†’            break;
449â†’        }
450â†’        if let Some(timeout) = config.timeout_explore
451â†’            && explore_start.elapsed() >= timeout
452â†’        {
453â†’            termination_reason = TerminationReason::TimeoutExplore;
454â†’            break;
455â†’        }
456â†’        if config.plateau_threshold > 0 && plateau_counter >= config.plateau_threshold {
457â†’            termination_reason = TerminationReason::CoveragePlateau;
458â†’            break;
459â†’        }
460â†’
461â†’        // Triage: predict whether this input will produce a novel path.
462â†’        // Skip triage for user-provided inputs â€” always execute those.
463â†’        let is_sampled_skip = if entry.source != InputSource::UserProvided {
464â†’            let verdict = triage_state.triage_candidate(&entry.inputs, &covered_paths);
465â†’            triage_state.record_verdict(&verdict);
466â†’            if verdict == TriageVerdict::Skip {
467â†’                if triage_state.should_sample() {
468â†’                    // Execute anyway to validate the prediction.
469â†’                    true
470â†’                } else {
471â†’                    triage_skipped += 1;
472â†’                    continue;
473â†’                }
474â†’            } else {
475â†’                false
476â†’            }
477â†’        } else {
478â†’            false
479â†’        };
480â†’
481â†’        // Execute concretely via the frontend.
482â†’        let response = frontend
483â†’            .send(Command::Execute {
484â†’                function: function_name.to_string(),
485â†’                inputs: entry.inputs.clone(),
486â†’                mocks: config.mocks.clone(),
487â†’                setup_context: None,
488â†’            })
489â†’            .await?;
490â†’
491â†’        total_executions += 1;
492â†’
493â†’        let exec_result = match response.result {
494â†’            ResponseResult::Execute(result) => *result,
495â†’            ResponseResult::Error { message, .. } => {
496â†’                // Frontend reported an error â€” skip this input but continue exploring.
497â†’                log::warn!("frontend error during execute: {message}");
498â†’                continue;
499â†’            }
500â†’            _ => continue,
501â†’        };
502â†’
503â†’        // Record raw result for pipeline composability.
504â†’        raw_results.push((entry.inputs.clone(), exec_result.clone()));
505â†’
506â†’        let path_id = hash_branch_path(&exec_result.branch_path);
507â†’
508â†’        // Validate sampled skip prediction before modifying covered_paths.
509â†’        if is_sampled_skip {
510â†’            let already_covered = covered_paths.contains(&path_id);
511â†’            // Sentinel values: equal if prediction correct, different if misprediction.
512â†’            triage_state.record_sample(0, if already_covered { 0 } else { 1 });
513â†’            if !already_covered {
514â†’                triage_mispredictions += 1;
515â†’            }
516â†’        }
517â†’
518â†’        if !covered_paths.insert(path_id) {
519â†’            // Already covered this path â€” skip solving.
520â†’            plateau_counter += 1;
521â†’            continue;
522â†’        }
523â†’
524â†’        // New path discovered â€” reset plateau counter and update triage state.
525â†’        plateau_counter = 0;
526â†’        triage_state.update(&exec_result.branch_path);
527â†’
528â†’        // Track per-branch discovery attribution from input source.
529â†’        let method = match entry.source {
530â†’            InputSource::Z3Solved => DiscoveryMethod::Z3,
531â†’            InputSource::UserProvided => DiscoveryMethod::UserProvided,
532â†’            InputSource::Drilled => DiscoveryMethod::Drilled,
533â†’            InputSource::Seed | InputSource::Fuzzed => DiscoveryMethod::Random,
534â†’        };
535â†’        for decision in &exec_result.branch_path {
536â†’            if seen_branch_ids.insert(decision.branch_id) {
537â†’                discoveries.push((decision.branch_id, method));
538â†’            }
539â†’        }
540â†’
541â†’        // Update frontier set: track which branch sides have been seen.
542â†’        for decision in &exec_result.branch_path {
543â†’            seen_branch_sides.insert((decision.branch_id, decision.taken));
544â†’            let opposite_seen =
545â†’                seen_branch_sides.contains(&(decision.branch_id, !decision.taken));
546â†’            if opposite_seen {
547â†’                // Both sides explored â€” no longer a frontier.
548â†’                frontier_set.remove(decision.branch_id);
549â†’            } else {
550â†’                // Still a frontier â€” insert or update with current inputs as best_prefix.
551â†’                let prev_stall = frontier_set
552â†’                    .iter()
553â†’                    .find(|f| f.branch_id == decision.branch_id)
554â†’                    .map_or(0, |f| f.stall_count);
555â†’                let blocking =
556â†’                    drilling::identify_blocking_params(&decision.constraint, param_infos);
557â†’                let depth =
558â†’                    drilling::branch_depth(&exec_result.branch_path, decision.branch_id);
559â†’                frontier_set.insert(Frontier {
560â†’                    branch_id: decision.branch_id,
561â†’                    depth,
562â†’                    blocking_params: blocking,
563â†’                    best_prefix: entry.inputs.clone(),
564â†’                    stall_count: prev_stall,
565â†’                });
566â†’            }
567â†’        }
568â†’
569â†’        // Extract symbolic constraints from the branch path.
570â†’        let sym_constraints = extract_sym_constraints(&exec_result);
571â†’
572â†’        // Collect solvable constraints with their original branch_path indices
573â†’        // so we can attribute stalls back to specific frontiers.
574â†’        let solvable_with_idx: Vec<(usize, SymExpr)> = sym_constraints
575â†’            .iter()
576â†’            .enumerate()
577â†’            .filter_map(|(i, c)| c.as_ref().map(|e| (i, e.clone())))
578â†’            .collect();
579â†’        let solvable: Vec<SymExpr> = solvable_with_idx.iter().map(|(_, e)| e.clone()).collect();
580â†’
581â†’        // Try to negate each branch constraint with Z3.
582â†’        if !solvable.is_empty() {
583â†’            for (solve_idx, &(branch_idx, _)) in solvable_with_idx.iter().enumerate() {
584â†’                match solver::solve_for_new_path(&solvable, solve_idx, config.solver_timeout_ms, param_infos) {
585â†’                    Ok(SolveResult::Sat(values)) => {
586â†’                        let new_inputs =
587â†’                            overlay_solved_values(&entry.inputs, &values, &param_names);
588â†’                        worklist.push(WorklistEntry {
589â†’                            inputs: new_inputs,
590â†’                            source: InputSource::Z3Solved,
591â†’                        });
592â†’                        z3_generated += 1;
593â†’                    }
594â†’                    Ok(SolveResult::Unsat) => {
595â†’                        // Infeasible â€” increment stall for the corresponding frontier.
596â†’                        if let Some(bd) = exec_result.branch_path.get(branch_idx) {
597â†’                            frontier_set.increment_stall(bd.branch_id);
598â†’                        }
599â†’                    }

400â†’/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
401â†’/// branches) suggests intentional input rejection. Errors without a preceding guard
402â†’/// or deep in the branch path are more likely accidental.
403â†’pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
404â†’    let error = result.thrown_error.as_ref()?;
405â†’
406â†’    // If the frontend already classified this as infrastructure, trust it
407â†’    if error.error_category.as_deref() == Some("infrastructure") {
408â†’        return Some(ErrorIntentLabel {
409â†’            label: "likely_runtime".into(),
410â†’            confidence: 0.9,
411â†’        });
412â†’    }
413â†’
414â†’    let branch_path = &result.branch_path;
415â†’    if branch_path.is_empty() {
416â†’        // No branch data â€” can't infer intent
417â†’        return Some(ErrorIntentLabel {
418â†’            label: "unknown".into(),
419â†’            confidence: 0.0,
420â†’        });
421â†’    }
422â†’
423â†’    // Check the last branch before the error
424â†’    let last_branch = branch_path.last().unwrap();
425â†’
426â†’    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
427â†’    // Shallow depth (few branches) + guard = likely validation.
428â†’    if last_branch.taken && branch_path.len() <= 3 {
429â†’        return Some(ErrorIntentLabel {
430â†’            label: "likely_validation".into(),
431â†’            confidence: 0.7,
432â†’        });
433â†’    }
434â†’
435â†’    // Deep branch path with error = likely accidental runtime failure
436â†’    if branch_path.len() > 5 {
437â†’        return Some(ErrorIntentLabel {
438â†’            label: "likely_runtime".into(),
439â†’            confidence: 0.6,
440â†’        });
441â†’    }
442â†’
443â†’    // Frontend-level classification can help disambiguate
444â†’    if error.error_category.as_deref() == Some("validation") {
445â†’        return Some(ErrorIntentLabel {
446â†’            label: "likely_validation".into(),
447â†’            confidence: 0.8,
