  1â†’//! Parameter drilling: focused mutation of blocking parameters on stalled frontiers.
  2â†’//!
  3â†’//! When the Z3 solver returns Unsat/Error for a branch and naive fuzzing hasn't
  4â†’//! flipped it, the branch stalls. Drilling pins non-blocking parameters at their
  5â†’//! best-known values and applies intensive type-aware mutation only to the
  6â†’//! parameter(s) appearing in the branch's symbolic constraint.
  7â†’
  8â†’use rand::Rng;
  9â†’use serde_json::Value;
 10â†’
 11â†’use crate::execution_record::SymConstraint;
 12â†’use crate::input_gen::mutate_value;
 13â†’use crate::sym_expr::extract_param_names;
 14â†’use crate::types::ParamInfo;
 15â†’
 16â†’/// Number of drilled mutations generated per blocking parameter per frontier.
 17â†’pub const DRILL_MUTATIONS_PER_PARAM: usize = 4;
 18â†’
 19â†’/// Stall count threshold before drilling activates for a frontier.
 20â†’pub const DRILL_STALL_THRESHOLD: u32 = 2;
 21â†’
 22â†’/// Maximum number of stalled frontiers to drill per exploration round.
 23â†’pub const MAX_FRONTIERS_PER_ROUND: usize = 3;
 24â†’
 25â†’/// Map parameter names from a branch constraint to their indices in `param_infos`.
 26â†’///
 27â†’/// For `SymConstraint::Expr`, walks the symbolic expression tree to extract
 28â†’/// referenced parameter names, then resolves each to its positional index.
 29â†’/// Returns an empty vec for `Unknown` constraints (no symbolic info available).
 30â†’pub fn identify_blocking_params(
 31â†’    constraint: &SymConstraint,
 32â†’    param_infos: &[ParamInfo],
 33â†’) -> Vec<usize> {
 34â†’    let expr = match constraint {
 35â†’        SymConstraint::Expr { expr } => expr,
 36â†’        SymConstraint::Unknown { .. } => return vec![],
 37â†’    };
 38â†’
 39â†’    let names = extract_param_names(expr);
 40â†’    let mut indices: Vec<usize> = names
 41â†’        .iter()
 42â†’        .filter_map(|name| param_infos.iter().position(|p| p.name == *name))
 43â†’        .collect();
 44â†’    indices.sort_unstable();
 45â†’    indices.dedup();
 46â†’    indices
 47â†’}
 48â†’
 49â†’/// Generate drilled inputs: pin non-blocking params at `best_prefix` values,
 50â†’/// intensively mutate only the blocking parameter(s).
 51â†’///
 52â†’/// If `blocking_params` is empty, falls back to mutating all parameters.
 53â†’/// Returns up to `count` mutated input vectors.
 54â†’pub fn generate_drilled_inputs(
 55â†’    best_prefix: &[Value],
 56â†’    blocking_params: &[usize],
 57â†’    param_infos: &[ParamInfo],
 58â†’    count: usize,
 59â†’    rng: &mut impl Rng,
 60â†’) -> Vec<Vec<Value>> {
 61â†’    if best_prefix.is_empty() || param_infos.is_empty() {
 62â†’        return vec![];
 63â†’    }
 64â†’
 65â†’    let targets: Vec<usize> = if blocking_params.is_empty() {
 66â†’        // No blocking info â€” mutate all params as fallback.
 67â†’        (0..best_prefix.len().min(param_infos.len())).collect()
 68â†’    } else {
 69â†’        blocking_params
 70â†’            .iter()
 71â†’            .copied()
 72â†’            .filter(|&i| i < best_prefix.len() && i < param_infos.len())
 73â†’            .collect()
 74â†’    };
 75â†’
 76â†’    if targets.is_empty() {
 77â†’        return vec![];
 78â†’    }
 79â†’
 80â†’    let mut results = Vec::with_capacity(count);
 81â†’    for _ in 0..count {
 82â†’        let mut inputs = best_prefix.to_vec();
 83â†’        for &idx in &targets {
 84â†’            inputs[idx] = mutate_value(&best_prefix[idx], &param_infos[idx].typ, &[], rng);
 85â†’        }
 86â†’        results.push(inputs);
 87â†’    }
 88â†’    results
 89â†’}
 90â†’
 91â†’/// Resolve the depth (position in branch path) of a branch_id from an
 92â†’/// execution's branch_path. Returns 0 if not found.
 93â†’pub fn branch_depth(
 94â†’    branch_path: &[crate::execution_record::BranchDecision],
 95â†’    branch_id: u32,
 96â†’) -> u32 {
 97â†’    branch_path
 98â†’        .iter()
 99â†’        .position(|d| d.branch_id == branch_id)
100â†’        .map_or(0, |i| i as u32)
101â†’}
